describe('ShoppingCart', () => {
  it('starts empty with zero subtotal and zero total', () => {
    const cart = new ShoppingCart()

    expect(cart.items()).toEqual([])
    expect(cart.subtotal()).toBe(0)
    expect(cart.total()).toBe(0)
  })

  it('can add an item and compute subtotal', () => {
    const cart = new ShoppingCart()

    cart.addItem({
      productId: 'book-1',
      name: 'Book',
      price: 29.99,
      quantity: 3,
    })

    expect(cart.items()).toEqual([
      {
        productId: 'book-1',
        name: 'Book',
        price: 29.99,
        quantity: 3,
      },
    ])
    expect(cart.subtotal()).toBeCloseTo(89.97)
    expect(cart.total()).toBeCloseTo(89.97)
  })
})
